from __future__ import annotations

import json
from dataclasses import dataclass
from pathlib import Path
from typing import Any

import pandas as pd

from quantresearch.preprocessing.ml_dataset import leakage_prone_feature_columns

DEFAULT_PRODUCTION_LABEL = "a_share_all_v1_full_20260424"
DEFAULT_PRODUCTION_ML_READY_DIR = Path("data_lake/curated/ml_ready_v1") / DEFAULT_PRODUCTION_LABEL
DEFAULT_PRODUCTION_OBSERVATION_QUALITY = (
    Path("data_lake/curated/noise_bias_v1") / "a_share_all_v1" / DEFAULT_PRODUCTION_LABEL / "observation_quality.parquet"
)
DEFAULT_PRODUCTION_EVENTS = DEFAULT_PRODUCTION_ML_READY_DIR / "events.parquet"
DEFAULT_STOCK_MASTER_PATCH = Path("data_lake/curated/baostock_reference_v1/stock_basic_patch_v1/stock_master_patched.parquet")
DEFAULT_BENCHMARK_CONSTITUENTS = Path(
    "data_lake/curated/benchmark_constituents_v1/a_share_coverage_20080101_20260424/benchmark_constituents.parquet"
)

EXPECTED_POLICY_VALUES: dict[str, object] = {
    "stock_code_alias_policy": "drop_confirmed_old_code_alias_rows",
    "event_feature_policy": "diagnostics_only",
    "pit_industry_policy": "capco_csrc_l1_official_first_baostock_gap_fill_known_at",
    "validation_scheme": "expanding_gap",
    "validation_hold_days": 20,
    "transform_fit_policy": "cross_sectional_transforms_by_signal_date; fitted_imputers_exclude_final_holdout",
}
EXPECTED_PREPROCESS_SPECS = ("raw", "winsor_rank_cs", "robust_z_cs")
REQUIRED_MANIFEST_FILES = (
    "monthly_universe",
    "benchmark_constituents",
    "benchmark_availability",
    "official_benchmark_returns",
    "benchmark_return_panel",
    "observation_quality",
    "events",
    "event_windows",
    "pit_industry_history",
    "etf_proxy_returns",
    "fundamental_features",
    "stock_code_aliases",
)
REQUIRED_ARTIFACTS = (
    "features.parquet",
    "labels.parquet",
    "splits.parquet",
    "sample_manifest.json",
    "event_windows.parquet",
    "feature_leakage_audit.csv",
    "preprocess_audit.csv",
    "feature_coverage.csv",
    "trial_ledger.csv",
    "sample_uniqueness.parquet",
    "macro_event_quality_report.json",
    "macro_event_source_catalog.csv",
    "macro_vintages.parquet",
    "gdelt_doc_articles.parquet",
    "gdelt_extract_audit.csv",
)


@dataclass(frozen=True)
class GateIssue:
    severity: str
    code: str
    message: str


@dataclass(frozen=True)
class MlReadyGateResult:
    status: str
    issues: tuple[GateIssue, ...]
    rows: int
    feature_columns: int
    label_rows: int
    duplicate_feature_keys: int
    duplicate_label_keys: int
    key_sets_equal: bool

    def to_payload(self) -> dict[str, object]:
        return {
            "status": self.status,
            "rows": self.rows,
            "feature_columns": self.feature_columns,
            "label_rows": self.label_rows,
            "duplicate_feature_keys": self.duplicate_feature_keys,
            "duplicate_label_keys": self.duplicate_label_keys,
            "key_sets_equal": self.key_sets_equal,
            "severity_counts": {
                severity: sum(1 for issue in self.issues if issue.severity == severity) for severity in ("hard_fail", "warn", "info")
            },
            "issues": [issue.__dict__ for issue in self.issues],
        }


def _read_manifest(path: Path) -> dict[str, Any]:
    if not path.exists():
        return {}
    return json.loads(path.read_text())


def _issue(issues: list[GateIssue], severity: str, code: str, message: str) -> None:
    issues.append(GateIssue(severity=severity, code=code, message=message))


def _key_set(frame: pd.DataFrame) -> set[tuple[str, str]]:
    return set(map(tuple, frame[["ts_code", "signal_date"]].astype(str).to_numpy()))


def validate_ml_ready_dataset(ml_ready_dir: Path) -> MlReadyGateResult:
    issues: list[GateIssue] = []
    ml_ready_dir = ml_ready_dir.expanduser()
    for filename in REQUIRED_ARTIFACTS:
        path = ml_ready_dir / filename
        if not path.exists():
            _issue(issues, "hard_fail", "missing_artifact", f"missing required artifact: {path}")

    features_path = ml_ready_dir / "features.parquet"
    labels_path = ml_ready_dir / "labels.parquet"
    manifest_path = ml_ready_dir / "sample_manifest.json"
    leakage_path = ml_ready_dir / "feature_leakage_audit.csv"
    splits_path = ml_ready_dir / "splits.parquet"
    event_windows_path = ml_ready_dir / "event_windows.parquet"
    macro_vintages_path = ml_ready_dir / "macro_vintages.parquet"
    macro_source_catalog_path = ml_ready_dir / "macro_event_source_catalog.csv"

    features = pd.read_parquet(features_path) if features_path.exists() else pd.DataFrame()
    labels = pd.read_parquet(labels_path) if labels_path.exists() else pd.DataFrame()
    feature_columns = int(len(features.columns))
    label_rows = int(len(labels))
    rows = int(len(features))

    for name, frame in (("features", features), ("labels", labels)):
        missing = {"ts_code", "signal_date"} - set(frame.columns)
        if missing:
            _issue(issues, "hard_fail", f"{name}_missing_keys", f"{name} missing key columns: {sorted(missing)}")

    duplicate_feature_keys = (
        int(features.duplicated(["ts_code", "signal_date"]).sum()) if {"ts_code", "signal_date"}.issubset(features.columns) else 0
    )
    duplicate_label_keys = (
        int(labels.duplicated(["ts_code", "signal_date"]).sum()) if {"ts_code", "signal_date"}.issubset(labels.columns) else 0
    )
    if duplicate_feature_keys:
        _issue(issues, "hard_fail", "duplicate_feature_keys", f"features duplicate keys: {duplicate_feature_keys}")
    if duplicate_label_keys:
        _issue(issues, "hard_fail", "duplicate_label_keys", f"labels duplicate keys: {duplicate_label_keys}")

    key_sets_equal = False
    if {"ts_code", "signal_date"}.issubset(features.columns) and {"ts_code", "signal_date"}.issubset(labels.columns):
        key_sets_equal = _key_set(features) == _key_set(labels)
        if not key_sets_equal:
            _issue(issues, "hard_fail", "feature_label_key_mismatch", "features and labels key sets differ")

    blocked_features = leakage_prone_feature_columns(features) if not features.empty else []
    if blocked_features:
        _issue(issues, "hard_fail", "leakage_features_present", f"leakage-prone feature columns remain: {blocked_features[:20]}")

    if leakage_path.exists():
        leakage_audit = pd.read_csv(leakage_path)
        if leakage_audit.empty:
            _issue(issues, "warn", "empty_feature_leakage_audit", "feature_leakage_audit.csv is empty")
    if splits_path.exists():
        splits = pd.read_parquet(splits_path)
        if splits.empty:
            _issue(issues, "hard_fail", "empty_splits", "splits.parquet is empty")
    if event_windows_path.exists():
        event_windows = pd.read_parquet(event_windows_path)
        if event_windows.empty:
            _issue(issues, "hard_fail", "empty_event_windows", "event_windows.parquet is empty")
    if macro_vintages_path.exists():
        macro_vintages = pd.read_parquet(macro_vintages_path)
        if macro_vintages.empty:
            _issue(issues, "hard_fail", "empty_macro_vintages", "macro_vintages.parquet is empty")
    if macro_source_catalog_path.exists():
        macro_source_catalog = pd.read_csv(macro_source_catalog_path)
        if macro_source_catalog.empty:
            _issue(issues, "hard_fail", "empty_macro_source_catalog", "macro_event_source_catalog.csv is empty")
    macro_quality_path = ml_ready_dir / "macro_event_quality_report.json"
    if macro_quality_path.exists():
        macro_quality = _read_manifest(macro_quality_path)
        if macro_quality.get("policy", {}).get("macro_surprise") != "disabled_until_licensed_consensus_source":
            _issue(issues, "hard_fail", "macro_surprise_policy_missing", "macro surprise must stay disabled without licensed consensus")
        if macro_quality.get("policy", {}).get("gpr") != "diagnostics_only_current_vintage_revised":
            _issue(issues, "hard_fail", "gpr_policy_mismatch", "GPR must remain diagnostics-only unless real vintages are added")

    manifest = _read_manifest(manifest_path)
    policy_versions = manifest.get("policy_versions", {}) if manifest else {}
    for key, expected in EXPECTED_POLICY_VALUES.items():
        observed = policy_versions.get(key)
        if observed != expected:
            _issue(issues, "hard_fail", "policy_mismatch", f"{key} expected {expected!r}, observed {observed!r}")
    observed_specs = tuple(policy_versions.get("preprocess_specs", ()))
    if observed_specs != EXPECTED_PREPROCESS_SPECS:
        _issue(
            issues,
            "hard_fail",
            "preprocess_spec_mismatch",
            f"preprocess_specs expected {EXPECTED_PREPROCESS_SPECS}, observed {observed_specs}",
        )

    manifest_files = manifest.get("files", {}) if manifest else {}
    for name in REQUIRED_MANIFEST_FILES:
        file_info = manifest_files.get(name)
        if not file_info:
            _issue(issues, "hard_fail", "manifest_missing_input", f"manifest missing input file entry: {name}")
            continue
        if not bool(file_info.get("exists")):
            _issue(issues, "hard_fail", "manifest_input_missing_on_disk", f"manifest input missing on disk: {name}")
        if not str(file_info.get("sha256", "")):
            _issue(issues, "hard_fail", "manifest_input_unhashed", f"manifest input has no sha256: {name}")

    hard_fails = sum(1 for issue in issues if issue.severity == "hard_fail")
    status = "passed" if hard_fails == 0 else "failed"
    return MlReadyGateResult(
        status=status,
        issues=tuple(issues),
